import{_ as i,o as n,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"100. Clinical Supervision","description":"","frontmatter":{"title":"100. Clinical Supervision","eba":"Mental Health Services 2024-2028","topics":["education-pd"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/education-pd/100-clinical-supervision.md","filePath":"ebas/mental-health/rpn-pen-mho/education-pd/100-clinical-supervision.md"}'),s={name:"ebas/mental-health/rpn-pen-mho/education-pd/100-clinical-supervision.md"};function a(t,e,l,p,c,u){return n(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_100-clinical-supervision" tabindex="-1">100. Clinical Supervision <a class="header-anchor" href="#_100-clinical-supervision" aria-label="Permalink to &quot;100. Clinical Supervision&quot;">​</a></h1><p><strong>100.1</strong> Introduction</p><p>Clinical supervision is an important mechanism to promote the learning, professional development and wellbeing of Employees and the delivery of safe, high-quality care to consumers of mental health and wellbeing services.</p><p><strong>100.2</strong> Description</p><p><strong>(a)</strong> Clinical supervision is a process of professional support and learning in which Employees are assisted to develop their clinical practice through regular time spent in reflective discussion with experienced and knowledgeable colleagues who are adequately trained in providing clinical supervision. The primary intention of (b) the interaction is to enhance clinical knowledge, skills and attitudes.</p><p><strong>(b)</strong> Clinical supervision is not student supervision, line management/operational supervision, a line management tool, counselling, performance management, a performance review process, or a form of preceptorship or training (and these processes will be conducted separately from clinical supervision). Clinical supervision will not be used as a method of surveillance.</p><p><strong>(c)</strong> Clinical Supervision is not a compulsory element of employment and is participated in on a voluntary basis.</p><p><strong>(d)</strong> Clinical supervision will be guided by the Clinical supervision for mental health nurses: A framework for Victoria (or successor).</p><p><strong>100.3</strong> Entitlement</p><p><strong>(a)</strong> A maximum of two (2) hours per month of clinical supervision is to be offered to all Employees covered by this section of the Agreement (including MHOs and clinical supervisors). Clinical supervision may be delivered on a one-on-one or group basis. The precise length of time will be subject to agreement between the supervisor and supervisee.</p><p><strong>(b)</strong> An Employee may request additional clinical supervision to the amount described at clause (a). In deciding whether to approve their request, the Employer will consider the Employee’s reasons for requesting the additional supervision and the Employer’s operational requirements. This clause does not prevent an Employer offering additional clinical supervision on a needs basis.</p><p><strong>100.4</strong> Supervision arrangements</p><p><strong>(a)</strong> Clinical supervision will be provided by a clinical supervisor of the Employee’s choice, subject to the requirements of this clause, agreement by the proposed supervisor and agreement by the employer. The Employer will not unreasonably refuse to agree. The external source may include existing reciprocal supervision arrangements with other mental health and wellbeing services.</p><p><strong>(b)</strong> All clinical supervisors must have received clinical supervision and undertaken clinical supervision training acceptable to the Employer.</p><p><strong>(c)</strong> Clinical supervision will not be provided by the Employee’s line manager/supervisor.</p><p><strong>(d)</strong> An Employee may request a change of clinical supervisor at any time.</p><p><strong>(e)</strong> Clinical supervision will occur on rostered time, at a time mutually agreed</p><p><strong>100.5</strong> Supervision training</p><p><strong>(a)</strong> Where an Employer and Employee agree for the Employee to become a clinical supervisor, the Employee will be provided access to appropriate clinical supervision training before they start delivering clinical supervision. The particular</p><p>training undertaken will be agreed between the Employee and Employer. The training will be completed on paid time. Requests from Employees to undertake supervision training will be directed to the Employee’s line manager and will be responded to within 14 days.</p><p><strong>100.6</strong> Access to record of clinical supervisors</p><p><strong>(a)</strong> Employers will maintain and make available to Employees a record of trained supervisors who, subject to their availability, are able to provide clinical supervision to Employees.</p>',22)])])}const g=i(s,[["render",a]]);export{m as __pageData,g as default};
